73	        vm->scope_absolute = njs_arr_create(vm->mem_pool, 8,
74	                                            sizeof(njs_value_t *));
75	        if (njs_slow_path(vm->scope_absolute == NULL)) {
76	            return NJS_INDEX_ERROR;
77	        }
78	    }
