84	        return NJS_INDEX_ERROR;
85	    }
86	
87	    *values = value;
88	
89	    vm->levels[NJS_LEVEL_STATIC] = vm->scope_absolute->start;
90	
91	    *retval = njs_scope_index(NJS_SCOPE_GLOBAL, index, NJS_LEVEL_STATIC,
92	                              NJS_VARIABLE_VAR);
93	
94	    return *retval;
95	}
