105	static njs_int_t
106	njs_scope_values_hash_test(njs_flathsh_query_t *fhq, void *data)
107	{
108	    njs_str_t    string;
109	    njs_value_t  *value;
110	
111	    value = *(njs_value_t **) data;
112	
113	    if (njs_is_string(value)) {
114	        /* parser strings are always initialized. */
115	        njs_string_get_unsafe(value, &string);
116	
117	    } else {
118	        string.start = (u_char *) value;
119	        string.length = sizeof(njs_value_t);
120	    }
121	
122	    if (fhq->key.length == string.length
123	        && memcmp(fhq->key.start, string.start, string.length) == 0)
124	    {
125	        return NJS_OK;
126	    }
127	
128	    return NJS_DECLINED;
129	}
130	
131	
132	static const njs_flathsh_proto_t  njs_values_hash_proto
133	    njs_aligned(64) =
134	{
135	    njs_scope_values_hash_test,
136	    njs_flathsh_proto_alloc,
137	    njs_flathsh_proto_free,
138	};
139	
140	
141	/*
142	 * Constant values such as njs_value_true are copied to values_hash during
143	 * code generation when they are used as operands to guarantee aligned value.
144	 */
145	
146	static njs_value_t *
147	njs_scope_value_index(njs_vm_t *vm, const njs_value_t *src, njs_uint_t runtime,
148	    njs_index_t **index)
149	{
150	    u_char               *start;
151	    uint32_t             value_size, size, length;
152	    njs_int_t            ret;
153	    njs_str_t            str;
154	    njs_bool_t           is_string;
155	    njs_value_t          *value;
156	    njs_string_t         *string;
157	    njs_flathsh_t        *values_hash;
158	    njs_object_prop_t    *pr;
159	    njs_flathsh_query_t  fhq;
160	
161	    /* Suppress "may be used uninitialized" warning. */
162	    length = 0;
163	
164	    is_string = 0;
165	    value_size = sizeof(njs_value_t);
166	
167	    if (njs_is_string(src)) {
168	        /* parser strings are always initialized. */
169	        njs_string_get_unsafe(src, &str);
170	
171	        size = (uint32_t) str.length;
172	        start = str.start;
173	
174	        is_string = 1;
175	
176	    } else {
177	        size = value_size;
178	        start = (u_char *) src;
179	    }
180	
181	    fhq.key_hash = njs_djb_hash(start, size);
182	    fhq.key.length = size;
183	    fhq.key.start = start;
184	    fhq.proto = &njs_values_hash_proto;
185	
186	    if (njs_flathsh_find(&vm->shared->values_hash, &fhq) == NJS_OK) {
187	        value = ((njs_object_prop_t *) fhq.value)->u.val;
188	
189	        *index = (njs_index_t *) ((u_char *) value + sizeof(njs_value_t));
190	
191	    } else if (runtime && njs_flathsh_find(&vm->values_hash, &fhq) == NJS_OK) {
192	        value = ((njs_object_prop_t *) fhq.value)->u.val;
193	
194	        *index = (njs_index_t *) ((u_char *) value + sizeof(njs_value_t));
195	
196	    } else {
197	        if (is_string) {
198	            length = src->string.data->length;
199	
200	            value_size += sizeof(njs_string_t)
201	                          + njs_string_data_size(size, length);
202	        }
203	
204	        value_size += sizeof(njs_index_t);
205	
206	        value = njs_mp_align(vm->mem_pool, sizeof(njs_value_t), value_size);
207	        if (njs_slow_path(value == NULL)) {
208	            return NULL;
209	        }
210	
211	        *value = *src;
212	
213	        if (is_string) {
214	            string = (njs_string_t *) ((u_char *) value + sizeof(njs_value_t)
215	                                       + sizeof(njs_index_t));
216	
217	            value->string.data = string;
218	
219	            njs_string_data_init(string, size, length);
220	
221	            memcpy(string->start, start, size);
222	        }
223	
224	        *index = (njs_index_t *) ((u_char *) value + sizeof(njs_value_t));
225	        **index = NJS_INDEX_ERROR;
226	
227	        fhq.replace = 0;
228	        fhq.pool = vm->mem_pool;
229	
230	        values_hash = runtime ? &vm->values_hash : &vm->shared->values_hash;
231	
232	        ret = njs_flathsh_insert(values_hash, &fhq);
233	        if (njs_slow_path(ret != NJS_OK)) {
234	            return NULL;
235	        }
236	
237	        pr = fhq.value;
238	        pr->u.val = value;
239	    }
240	
241	    if (start != (u_char *) src) {
242	        /*
243	         * The source node value must be updated with the shared value
244	         * allocated from the permanent memory pool because the node
245	         * value can be used as a variable initial value.
246	         */
247	        *(njs_value_t *) src = *value;
248	    }
249	
250	    return value;
251	}
